  ('social-worker-moex-07363', 'social-worker', 'social-worker-moex-101-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會福利中的私有福利（private welfare）的描述下列何者錯誤？', '["私有福利一直是英國社會主義經濟式照顧體系中的一環，儘管有其地位但卻被忽略", "私有福利之所以被忽視有二個因素，前者是政策分析者的學術興趣，另一種為戰後時期的政治形勢", "私有福利在1980年代至1990年代因英國保守黨相繼發展福利市場來改進服務的效率與效能而重新被 重視", "私有福利在英國新工黨執政後仍持續推動而民眾也意識到其重要性，而企業也做了相對的回應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d90f7a035be7", "answer_pdf_sha1": "0daae4475aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
